+package github.chains;
+
+import java.nio.file.Path;
+import java.nio.file.Paths;
+import spoon.Launcher;
+import spoon.reflect.CtModel;
+import spoon.reflect.code.CtTypeAccess;
+import spoon.reflect.declaration.CtElement;
+import spoon.reflect.factory.Factory;
+import spoon.reflect.reference.CtImport;
+import spoon.reflect.reference.CtPackageReference;
+import spoon.reflect.reference.CtTypeReference;
+import spoon.reflect.visitor.filter.TypeFilter;
+
+public class Main {
+    private static final String OLD_TYPE = "org.apache.struts2.dispatcher.ng.filter.StrutsPrepareAndExecuteFilter";
+    private static final String NEW_TYPE = "org.apache.struts2.dispatcher.filter.StrutsPrepareAndExecuteFilter";
+
+    public static void main(String[] args) {
+        if (args.length < 1) {
+            throw new IllegalArgumentException("Usage: Main <source-dir> [output-dir]");
+        }
+
+        Path sourceDir = Paths.get(args[0]);
+        Path outputDir = args.length > 1 ? Paths.get(args[1]) : sourceDir;
+
+        Launcher launcher = new Launcher();
+        launcher.getEnvironment().setNoClasspath(true);
+        launcher.getEnvironment().setAutoImports(true);
+        launcher.getEnvironment().setCommentEnabled(false);
+        launcher.getEnvironment().setComplianceLevel(17);
+        launcher.addInputResource(sourceDir.toString());
+        launcher.setSourceOutputDirectory(outputDir.toFile());
+
+        CtModel model = launcher.buildModel();
+        Factory factory = launcher.getFactory();
+
+        CtTypeReference<?> newType = factory.Type().createReference(NEW_TYPE);
+
+        for (CtTypeReference<?> typeReference : model.getElements(new TypeFilter<>(CtTypeReference.class))) {
+            if (OLD_TYPE.equals(typeReference.getQualifiedName())) {
+                replaceTypeReference(typeReference, newType, factory);
+            }
+        }
+
+        for (CtImport importRef : model.getElements(new TypeFilter<>(CtImport.class))) {
+            CtTypeReference<?> importedType = importRef.getReference();
+            if (importedType != null && OLD_TYPE.equals(importedType.getQualifiedName())) {
+                importRef.setReference(newType);
+            }
+        }
+
+        launcher.prettyprint();
+    }
+
+    private static void replaceTypeReference(
+            CtTypeReference<?> oldReference, CtTypeReference<?> newReference, Factory factory) {
+        CtTypeReference<?> replacement = newReference.clone();
+        CtElement parent = oldReference.getParent();
+
+        if (parent instanceof CtTypeAccess) {
+            ((CtTypeAccess<?>) parent).setAccessedType(replacement);
+            return;
+        }
+
+        if (parent instanceof CtPackageReference) {
+            ((CtPackageReference) parent).replace(replacement.getPackage());
+            return;
+        }
+
+        oldReference.replace(replacement);
+    }
+}
